import{_ as t,o as a,c as o,ae as d}from"./chunks/framework.Czhw_PXq.js";const _=JSON.parse('{"title":"导出普通 Java Method 文档","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/export-method-doc.md","filePath":"zh/guide/export-method-doc.md","lastUpdated":1776562190000}'),i={name:"zh/guide/export-method-doc.md"};function l(r,e,h,s,c,m){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="导出普通-java-method-文档" tabindex="-1">导出普通 Java Method 文档 <a class="header-anchor" href="#导出普通-java-method-文档" aria-label="Permalink to &quot;导出普通 Java Method 文档&quot;">​</a></h1><p>EasyYapi 可以导出普通 Java 方法的文档（不仅仅是 HTTP API）。这对于文档化服务方法、工具方法和其他非 HTTP 端点非常有用。</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><ol><li>打开包含要文档化的方法的文件</li><li>使用快捷键 <code>Alt + Shift + E</code> (Windows/Linux) 或 <code>Ctrl + E</code> (macOS)</li><li>选择要导出的方法</li><li>选择导出渠道并完成导出</li></ol><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>使用以下规则自定义方法文档：</p><ul><li><a href="/zh/settings/rules/mdoc_class_filter">mdoc.class.filter</a> — 过滤要包含的类</li><li><a href="/zh/settings/rules/mdoc_method_filter">mdoc.method.filter</a> — 过滤要包含的方法</li><li><a href="/zh/settings/rules/mdoc_method_path">mdoc.method.path</a> — 设置方法文档的路径</li><li><a href="/zh/settings/rules/mdoc_method_http_method">mdoc.method.http.method</a> — 设置方法文档的 HTTP 方法</li></ul>',7)])])}const p=t(i,[["render",l]]);export{_ as __pageData,p as default};
